/*
 * MultiInstance.dll
 *
 * Hooks mutex and process-creation APIs so that multiple instances of
 * DragonNest_x64.exe (and its child xcoronahost.xem) can run side-by-side.
 *
 * Mutex hooks  – rename target mutexes by appending the current PID so every
 *                instance owns a unique kernel object.
 *
 * CreateProcess hooks – when DragonNest_x64.exe spawns xcoronahost.xem, the
 *                       child is created suspended, this DLL is injected into
 *                       it, and then it is resumed. The child then has its own
 *                       copy of all hooks covering its mutex as well.
 *
 * Target mutexes:
 *   MutexDragonNest                      (DragonNest_x64.exe)
 *   ae0f623d247862c91f9e5e54142179ef0    (xcoronahost.xem)
 *
 * Hook library: MinHook (https://github.com/TsudaKageyu/minhook)
 */

#include <Windows.h>
#include <MinHook.h>

#include <string>
#include <string_view>

// Stored in DllMain so InjectDLL can resolve our own path on disk.
static HMODULE g_hSelf = nullptr;

// ─── Target mutex names ───────────────────────────────────────────────────────
// Both wide and ANSI lists must stay in sync.

static constexpr std::wstring_view kMutexW[] = {
    L"MutexDragonNest",
    L"ae0f623d247862c91f9e5e54142179ef0",
};
static constexpr std::string_view kMutexA[] = {
    "MutexDragonNest",
    "ae0f623d247862c91f9e5e54142179ef0",
};

// ─── Child process to propagate into ─────────────────────────────────────────

static constexpr std::wstring_view kChildExe = L"xcoronahost.xem";

// ─── Mutex matching ───────────────────────────────────────────────────────────
// Matches bare name ("MutexDragonNest") and namespace-prefixed forms
