 * Hooks CreateMutexW/A, CreateMutexExW/A, and OpenMutexW/A in kernel32 to
 * rename the target mutex "1.3.0.15" by appending the current process ID.
 * This lets multiple instances of DNLauncher.exe coexist without the second
 * instance seeing ERROR_ALREADY_EXISTS and bailing out.
 *
 * Hook library: MinHook (https://github.com/TsudaKageyu/minhook)
 */

#include <Windows.h>
#include <MinHook.h>

#include <string>
#include <string_view>

// ─── Target mutex name (short form, as passed to CreateMutex/OpenMutex) ──────

static constexpr std::wstring_view kTargetW = L"1.3.0.15";
static constexpr std::string_view  kTargetA =  "1.3.0.15";

// ─── Typedefs for original functions ─────────────────────────────────────────

using FnCreateMutexW   = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL,  LPCWSTR);
using FnCreateMutexA   = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL,  LPCSTR);
using FnCreateMutexExW = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCWSTR, DWORD, DWORD);
using FnCreateMutexExA = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCSTR,  DWORD, DWORD);
using FnOpenMutexW     = HANDLE(WINAPI*)(DWORD, BOOL, LPCWSTR);
using FnOpenMutexA     = HANDLE(WINAPI*)(DWORD, BOOL, LPCSTR);

static FnCreateMutexW   g_CreateMutexW   = nullptr;
static FnCreateMutexA   g_CreateMutexA   = nullptr;
static FnCreateMutexExW g_CreateMutexExW = nullptr;
static FnCreateMutexExA g_CreateMutexExA = nullptr;
static FnOpenMutexW     g_OpenMutexW     = nullptr;
static FnOpenMutexA     g_OpenMutexA     = nullptr;

// ─── Matching helpers ─────────────────────────────────────────────────────────
//
// Accepts any of: "1.3.0.15", "Global\1.3.0.15", "Local\1.3.0.15"
//

static bool IsTargetMutex(std::wstring_view name) {
    if (name == kTargetW) return true;
    if (name.size() > kTargetW.size()) {
        const size_t off = name.size() - kTargetW.size();
        if (name[off - 1] == L'\\' && name.substr(off) == kTargetW)
            return true;
    }
    return false;
}

static bool IsTargetMutex(std::string_view name) {
    if (name == kTargetA) return true;
    if (name.size() > kTargetA.size()) {
        const size_t off = name.size() - kTargetA.size();
        if (name[off - 1] == '\\' && name.substr(off) == kTargetA)
            return true;
    }
    return false;
}

// ─── PID-suffix helpers ───────────────────────────────────────────────────────

static std::wstring PidTagW() { return L"_" + std::to_wstring(GetCurrentProcessId()); }
static std::string  PidTagA() { return  "_" + std::to_string(GetCurrentProcessId());  }

// ─── Hook implementations ─────────────────────────────────────────────────────

HANDLE WINAPI Hook_CreateMutexW(LPSECURITY_ATTRIBUTES lpAttr, BOOL bOwner, LPCWSTR lpName) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::wstring(lpName) + PidTagW();
        return g_CreateMutexW(lpAttr, bOwner, newName.c_str());
    }
    return g_CreateMutexW(lpAttr, bOwner, lpName);
}

HANDLE WINAPI Hook_CreateMutexA(LPSECURITY_ATTRIBUTES lpAttr, BOOL bOwner, LPCSTR lpName) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::string(lpName) + PidTagA();
        return g_CreateMutexA(lpAttr, bOwner, newName.c_str());
    }
    return g_CreateMutexA(lpAttr, bOwner, lpName);
}

HANDLE WINAPI Hook_CreateMutexExW(LPSECURITY_ATTRIBUTES lpAttr, LPCWSTR lpName,
                                   DWORD dwFlags, DWORD dwDesiredAccess) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::wstring(lpName) + PidTagW();
        return g_CreateMutexExW(lpAttr, newName.c_str(), dwFlags, dwDesiredAccess);
    }
    return g_CreateMutexExW(lpAttr, lpName, dwFlags, dwDesiredAccess);
}

HANDLE WINAPI Hook_CreateMutexExA(LPSECURITY_ATTRIBUTES lpAttr, LPCSTR lpName,
                                   DWORD dwFlags, DWORD dwDesiredAccess) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::string(lpName) + PidTagA();
        return g_CreateMutexExA(lpAttr, newName.c_str(), dwFlags, dwDesiredAccess);
    }
    return g_CreateMutexExA(lpAttr, lpName, dwFlags, dwDesiredAccess);
}

HANDLE WINAPI Hook_OpenMutexW(DWORD dwAccess, BOOL bInherit, LPCWSTR lpName) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::wstring(lpName) + PidTagW();
        return g_OpenMutexW(dwAccess, bInherit, newName.c_str());
    }
    return g_OpenMutexW(dwAccess, bInherit, lpName);
}

HANDLE WINAPI Hook_OpenMutexA(DWORD dwAccess, BOOL bInherit, LPCSTR lpName) {
    if (lpName && IsTargetMutex(lpName)) {
        const auto newName = std::string(lpName) + PidTagA();
        return g_OpenMutexA(dwAccess, bInherit, newName.c_str());
    }
    return g_OpenMutexA(dwAccess, bInherit, lpName);
}

// ─── Hook installation/removal ────────────────────────────────────────────────

struct HookEntry {
    const wchar_t* module;
    const char*    proc;
    LPVOID         hookFn;
    LPVOID*        origFn;
};

static const HookEntry kHooks[] = {
    { L"kernel32", "CreateMutexW",   (LPVOID)Hook_CreateMutexW,   (LPVOID*)&g_CreateMutexW   },
    { L"kernel32", "CreateMutexA",   (LPVOID)Hook_CreateMutexA,   (LPVOID*)&g_CreateMutexA   },
    { L"kernel32", "CreateMutexExW", (LPVOID)Hook_CreateMutexExW, (LPVOID*)&g_CreateMutexExW },
    { L"kernel32", "CreateMutexExA", (LPVOID)Hook_CreateMutexExA, (LPVOID*)&g_CreateMutexExA },
    { L"kernel32", "OpenMutexW",     (LPVOID)Hook_OpenMutexW,     (LPVOID*)&g_OpenMutexW     },
    { L"kernel32", "OpenMutexA",     (LPVOID)Hook_OpenMutexA,     (LPVOID*)&g_OpenMutexA     },
};

static bool InstallHooks() {
    if (MH_Initialize() != MH_OK)
        return false;

    for (const auto& h : kHooks) {
        if (MH_CreateHookApi(h.module, h.proc, h.hookFn, h.origFn) != MH_OK)
            return false;
    }

    return MH_EnableHook(MH_ALL_HOOKS) == MH_OK;
}

static void RemoveHooks() {
    MH_DisableHook(MH_ALL_HOOKS);
    MH_Uninitialize();
}

// ─── DllMain ──────────────────────────────────────────────────────────────────

BOOL APIENTRY DllMain(HMODULE hModule, DWORD reason, LPVOID /*reserved*/) {
    switch (reason) {
    case DLL_PROCESS_ATTACH:
        DisableThreadLibraryCalls(hModule);
        InstallHooks();
        break;
    case DLL_PROCESS_DETACH:
        RemoveHooks();
        break;
    }
    return TRUE;
}

/*
 * Launcher.exe
 *
 * 1. Spawns DNLauncher.exe with CREATE_SUSPENDED so its main thread hasn't run yet.
 * 2. Injects MultiInstance.dll via the classic VirtualAllocEx/WriteProcessMemory/
 *    CreateRemoteThread(LoadLibraryW) technique.
 * 3. Waits for LoadLibrary to return (hooks are now installed inside the target).
 * 4. Resumes the main thread.
 *
 * Usage:
 *   Launcher.exe [target.exe] [hook.dll]
 *
 * Both arguments are optional; defaults are resolved relative to Launcher.exe's
 * own directory:
 *   target  -> <dir>\DNLauncher.exe
 *   hook    -> <dir>\MultiInstance.dll
 */

#include <Windows.h>

#include <filesystem>
#include <iostream>
#include <string>

namespace fs = std::filesystem;

// ─── Architecture helpers ─────────────────────────────────────────────────────

// Returns the PE Machine word from a file on disk (0x8664=x64, 0x14C=x86, 0=error).
static WORD PEMachine(const fs::path& exe) {
    HANDLE hFile = CreateFileW(exe.c_str(), GENERIC_READ, FILE_SHARE_READ,
                               nullptr, OPEN_EXISTING, 0, nullptr);
    if (hFile == INVALID_HANDLE_VALUE) return 0;

    IMAGE_DOS_HEADER dos{};
    DWORD read = 0;
    ReadFile(hFile, &dos, sizeof(dos), &read, nullptr);

    LONG peOffset = dos.e_lfanew;
    SetFilePointer(hFile, peOffset + 4, nullptr, FILE_BEGIN); // skip "PE\0\0"

    WORD machine = 0;
    ReadFile(hFile, &machine, sizeof(machine), &read, nullptr);
    CloseHandle(hFile);
    return machine;
}

static const wchar_t* MachineName(WORD m) {
    if (m == 0x8664) return L"x64";
    if (m == 0x014C) return L"x86 (32-bit)";
    return L"unknown";
}

// ─── Injection ────────────────────────────────────────────────────────────────

static bool InjectDLL(HANDLE hProcess, const std::wstring& absPath) {
    // Write the DLL path into the target process.
    const SIZE_T pathBytes = (absPath.size() + 1) * sizeof(wchar_t);

    LPVOID pRemote = VirtualAllocEx(hProcess, nullptr, pathBytes,
                                    MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (!pRemote) {
        std::wcerr << L"[!] VirtualAllocEx failed: " << GetLastError() << L"\n";
        return false;
    }

    if (!WriteProcessMemory(hProcess, pRemote, absPath.c_str(), pathBytes, nullptr)) {
        std::wcerr << L"[!] WriteProcessMemory failed: " << GetLastError() << L"\n";
        VirtualFreeEx(hProcess, pRemote, 0, MEM_RELEASE);
        return false;
    }

    // LoadLibraryW lives at the same VA in every process (kernel32 is relocated
    // once at boot and stays fixed for the session).
    auto pLoadLib = reinterpret_cast<LPTHREAD_START_ROUTINE>(
        GetProcAddress(GetModuleHandleW(L"kernel32.dll"), "LoadLibraryW"));

    if (!pLoadLib) {
        std::wcerr << L"[!] GetProcAddress(LoadLibraryW) failed: " << GetLastError() << L"\n";
        VirtualFreeEx(hProcess, pRemote, 0, MEM_RELEASE);
        return false;
    }

    // Spin up a remote thread that calls LoadLibraryW(path).
    // This thread runs independently of the still-suspended main thread.
    HANDLE hThread = CreateRemoteThread(hProcess, nullptr, 0,
                                        pLoadLib, pRemote, 0, nullptr);
    if (!hThread) {
        std::wcerr << L"[!] CreateRemoteThread failed: " << GetLastError() << L"\n";
        VirtualFreeEx(hProcess, pRemote, 0, MEM_RELEASE);
        return false;
    }

    // Wait for DllMain(DLL_PROCESS_ATTACH) to finish — hooks are live after this.
    WaitForSingleObject(hThread, INFINITE);

    DWORD exitCode = 0;
    GetExitCodeThread(hThread, &exitCode);   // exitCode == HMODULE (0 == failure)
    CloseHandle(hThread);
    VirtualFreeEx(hProcess, pRemote, 0, MEM_RELEASE);

    if (exitCode == 0) {
        std::wcerr << L"[!] LoadLibraryW returned NULL inside target process\n";
        return false;
    }
    return true;
}

// ─── Entry point ──────────────────────────────────────────────────────────────

int wmain(int argc, wchar_t* argv[]) {
    // Resolve self directory so defaults work regardless of cwd.
    wchar_t selfBuf[MAX_PATH]{};
    GetModuleFileNameW(nullptr, selfBuf, MAX_PATH);
    const fs::path selfDir = fs::path(selfBuf).parent_path();

    fs::path targetExe = selfDir / L"DNLauncher.exe";
    fs::path dllPath   = selfDir / L"MultiInstance.dll";

    if (argc >= 2) targetExe = argv[1];
    if (argc >= 3) dllPath   = argv[2];

    targetExe = fs::absolute(targetExe);
    dllPath   = fs::absolute(dllPath);

    // ── Sanity checks ────────────────────────────────────────────────────────
    if (!fs::exists(targetExe)) {
        std::wcerr << L"[!] Target not found: " << targetExe.wstring() << L"\n";
        return 1;
    }
    if (!fs::exists(dllPath)) {
        std::wcerr << L"[!] DLL not found: " << dllPath.wstring() << L"\n";
        return 1;
    }

    // ── Architecture guard ────────────────────────────────────────────────────
    const WORD targetMachine = PEMachine(targetExe);
    const WORD dllMachine    = PEMachine(dllPath);
#ifdef _WIN64
    const WORD selfMachine = 0x8664;
#else
    const WORD selfMachine = 0x014C;
#endif

    std::wcout << L"[*] Target : " << targetExe.wstring()
               << L"  [" << MachineName(targetMachine) << L"]\n";
    std::wcout << L"[*] DLL    : " << dllPath.wstring()
               << L"  [" << MachineName(dllMachine) << L"]\n";

    if (targetMachine != selfMachine || dllMachine != selfMachine) {
        std::wcerr << L"[!] Architecture mismatch!\n"
                   << L"    Launcher : " << MachineName(selfMachine)   << L"\n"
                   << L"    Target   : " << MachineName(targetMachine) << L"\n"
                   << L"    DLL      : " << MachineName(dllMachine)    << L"\n"
                   << L"    Rebuild all three for the same architecture.\n";
        return 1;
    }

    // ── Launch target process suspended ──────────────────────────────────────
    STARTUPINFOW si{};
    si.cb = sizeof(si);
    PROCESS_INFORMATION pi{};

    // Use the target's own directory as working directory so relative paths
    // inside DNLauncher.exe resolve correctly.
    const std::wstring workDir = targetExe.parent_path().wstring();

    if (!CreateProcessW(
            targetExe.c_str(),   // lpApplicationName
            nullptr,             // lpCommandLine  (no extra args)
            nullptr,             // lpProcessAttributes
            nullptr,             // lpThreadAttributes
            FALSE,               // bInheritHandles
            CREATE_SUSPENDED,    // dwCreationFlags  ← main thread starts paused
            nullptr,             // lpEnvironment
            workDir.c_str(),     // lpCurrentDirectory
            &si, &pi)) {
        std::wcerr << L"[!] CreateProcessW failed: " << GetLastError() << L"\n";
        return 1;
    }

    std::wcout << L"[*] PID " << pi.dwProcessId << L" created (suspended)\n";

    // ── Inject MultiInstance.dll ──────────────────────────────────────────────
    std::wcout << L"[*] Injecting DLL...\n";
    if (!InjectDLL(pi.hProcess, dllPath.wstring())) {
        std::wcerr << L"[!] Injection failed — terminating target\n";
        TerminateProcess(pi.hProcess, 1);
        CloseHandle(pi.hProcess);
        CloseHandle(pi.hThread);
        return 1;
    }

    // ── Resume the main thread — hooks are now live ───────────────────────────
    std::wcout << L"[+] DLL injected OK — resuming PID " << pi.dwProcessId << L"\n";
    ResumeThread(pi.hThread);

    CloseHandle(pi.hProcess);
    CloseHandle(pi.hThread);
    return 0;
}

