   264→    { L"kernel32", "OpenMutexA",     (LPVOID)Hook_OpenMutexA,     (LPVOID*)&g_OpenMutexA     },
   265→    { L"kernel32", "CreateProcessW", (LPVOID)Hook_CreateProcessW, (LPVOID*)&g_CreateProcessW },
   266→    { L"kernel32", "CreateProcessA", (LPVOID)Hook_CreateProcessA, (LPVOID*)&g_CreateProcessA },
   267→};
   268→
   269→static bool InstallHooks() {
   270→    if (MH_Initialize() != MH_OK) return false;
   271→    for (const auto& h : kHooks)
   272→        if (MH_CreateHookApi(h.mod, h.fn, h.hook, h.orig) != MH_OK) return false;
   273→    return MH_EnableHook(MH_ALL_HOOKS) == MH_OK;
   274→}
   275→
   276→static void RemoveHooks() {
   277→    MH_DisableHook(MH_ALL_HOOKS);
   278→    MH_Uninitialize();
   279→}
   280→
   281→// ─── DllMain ─────────────────────────────────────────────────────────────────
   282→
   283→BOOL APIENTRY DllMain(HMODULE hModule, DWORD reason, LPVOID /*reserved*/) {
   284→    switch (reason) {
   285→    case DLL_PROCESS_ATTACH:
   286→        DisableThreadLibraryCalls(hModule);
   287→        g_hSelf = hModule;   // needed for GetModuleFileNameW in PropagateToChild
   288→        InstallHooks();
   289→        break;
   290→    case DLL_PROCESS_DETACH:
   291→        RemoveHooks();
   292→        break;
   293→    }
   294→    return TRUE;
   295→}
