static bool IsTargetMutex(const Ch* raw,
                           const std::basic_string_view<Ch> (&list)[N]) {
    if (!raw) return false;
    std::basic_string_view<Ch> sv(raw);
    for (const auto& t : list) {
        if (sv == t) return true;
        if (sv.size() > t.size()) {
