    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessW(lpApp, lpCmd, lpPA, lpTA, bInherit,
                                     dwFlags | CREATE_SUSPENDED,
                                     lpEnv, lpCwd, lpSI, lpPI);
    if (ok) {
        PropagateToChild(lpPI->hProcess, lpApp, lpCmd);
        if (!wasSuspended) ResumeThread(lpPI->hThread);
    }
    return ok;
}

BOOL WINAPI Hook_CreateProcessA(
    LPCSTR lpApp, LPSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCSTR lpCwd,
    LPSTARTUPINFOA lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessA(lpApp, lpCmd, lpPA, lpTA, bInherit,
                                     dwFlags | CREATE_SUSPENDED,
                                     lpEnv, lpCwd, lpSI, lpPI);
    if (ok) {
        // Convert ANSI args to wide for the shared PropagateToChild helper.
        auto toWide = [](LPCSTR s) -> std::wstring {
            if (!s) return {};
            const int n = MultiByteToWideChar(CP_ACP, 0, s, -1, nullptr, 0);
            std::wstring w(n, L'\0');
            MultiByteToWideChar(CP_ACP, 0, s, -1, w.data(), n);
            return w;
        };
        const std::wstring wApp = toWide(lpApp);
        const std::wstring wCmd = toWide(lpCmd);
        PropagateToChild(lpPI->hProcess,
                         lpApp ? wApp.c_str() : nullptr,
                         lpCmd ? wCmd.c_str() : nullptr);
        if (!wasSuspended) ResumeThread(lpPI->hThread);
    }
    return ok;
}

// ─── Hook table & install/remove ─────────────────────────────────────────────

struct HookEntry { const wchar_t* mod; const char* fn; LPVOID hook; LPVOID* orig; };

static const HookEntry kHooks[] = {
    { L"kernel32", "CreateMutexW",   (LPVOID)Hook_CreateMutexW,   (LPVOID*)&g_CreateMutexW   },
    { L"kernel32", "CreateMutexA",   (LPVOID)Hook_CreateMutexA,   (LPVOID*)&g_CreateMutexA   },
    { L"kernel32", "CreateMutexExW", (LPVOID)Hook_CreateMutexExW, (LPVOID*)&g_CreateMutexExW },
    { L"kernel32", "CreateMutexExA", (LPVOID)Hook_CreateMutexExA, (LPVOID*)&g_CreateMutexExA },
    { L"kernel32", "OpenMutexW",     (LPVOID)Hook_OpenMutexW,     (LPVOID*)&g_OpenMutexW     },
    { L"kernel32", "OpenMutexA",     (LPVOID)Hook_OpenMutexA,     (LPVOID*)&g_OpenMutexA     },
    { L"kernel32", "CreateProcessW", (LPVOID)Hook_CreateProcessW, (LPVOID*)&g_CreateProcessW },
    { L"kernel32", "CreateProcessA", (LPVOID)Hook_CreateProcessA, (LPVOID*)&g_CreateProcessA },
};

static bool InstallHooks() {
    if (MH_Initialize() != MH_OK) return false;
    for (const auto& h : kHooks)
        if (MH_CreateHookApi(h.mod, h.fn, h.hook, h.orig) != MH_OK) return false;
    return MH_EnableHook(MH_ALL_HOOKS) == MH_OK;
}

static void RemoveHooks() {
    MH_DisableHook(MH_ALL_HOOKS);
    MH_Uninitialize();
}

// ─── DllMain ─────────────────────────────────────────────────────────────────

BOOL APIENTRY DllMain(HMODULE hModule, DWORD reason, LPVOID /*reserved*/) {
    switch (reason) {
    case DLL_PROCESS_ATTACH:
        DisableThreadLibraryCalls(hModule);
        g_hSelf = hModule;   // needed for GetModuleFileNameW in PropagateToChild
        InstallHooks();
        break;
    case DLL_PROCESS_DETACH:
        RemoveHooks();
        break;
    }
    return TRUE;
}

