static FnCreateProcessA      g_CreateProcessA      = nullptr;
static FnCreateProcessAsUserW g_CreateProcessAsUserW = nullptr;
static FnCreateProcessAsUserA g_CreateProcessAsUserA = nullptr;

// ─── Mutex hooks ──────────────────────────────────────────────────────────────

HANDLE WINAPI Hook_CreateMutexW(LPSECURITY_ATTRIBUTES a, BOOL b, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexW))
        return g_CreateMutexW(a, b, (std::wstring(name) + PidTagW()).c_str());
    return g_CreateMutexW(a, b, name);
}

HANDLE WINAPI Hook_CreateMutexA(LPSECURITY_ATTRIBUTES a, BOOL b, LPCSTR name) {
    if (IsTargetMutex(name, kMutexA))
        return g_CreateMutexA(a, b, (std::string(name) + PidTagA()).c_str());
    return g_CreateMutexA(a, b, name);
}

HANDLE WINAPI Hook_CreateMutexExW(LPSECURITY_ATTRIBUTES a, LPCWSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexW))
        return g_CreateMutexExW(a, (std::wstring(name) + PidTagW()).c_str(), f, d);
    return g_CreateMutexExW(a, name, f, d);
}

HANDLE WINAPI Hook_CreateMutexExA(LPSECURITY_ATTRIBUTES a, LPCSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexA))
        return g_CreateMutexExA(a, (std::string(name) + PidTagA()).c_str(), f, d);
    return g_CreateMutexExA(a, name, f, d);
}

HANDLE WINAPI Hook_OpenMutexW(DWORD acc, BOOL inh, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexW))
        return g_OpenMutexW(acc, inh, (std::wstring(name) + PidTagW()).c_str());
    return g_OpenMutexW(acc, inh, name);
}

HANDLE WINAPI Hook_OpenMutexA(DWORD acc, BOOL inh, LPCSTR name) {
    if (IsTargetMutex(name, kMutexA))
        return g_OpenMutexA(acc, inh, (std::string(name) + PidTagA()).c_str());
    return g_OpenMutexA(acc, inh, name);
}

// ─── CreateProcess* hooks (fast-path child propagation) ───────────────────────

static std::wstring ExeBasenameW(LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring src;
    if (lpApp && *lpApp) {
        src = lpApp;
    } else if (lpCmd && *lpCmd) {
        if (lpCmd[0] == L'"') {
            const wchar_t* end = wcschr(lpCmd + 1, L'"');
            src = end ? std::wstring(lpCmd + 1, end) : std::wstring(lpCmd + 1);
        } else {
            const wchar_t* end = wcschr(lpCmd, L' ');
            src = end ? std::wstring(lpCmd, end) : std::wstring(lpCmd);
        }
    }
    const size_t slash = src.rfind(L'\\');
    if (slash != std::wstring::npos) src = src.substr(slash + 1);
    for (auto& c : src) c = static_cast<wchar_t>(towlower(c));
    return src;
}

static void PropagateToChild(HANDLE hProcess, LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring target(kChildExe);
    for (auto& c : target) c = static_cast<wchar_t>(towlower(c));
    if (ExeBasenameW(lpApp, lpCmd) != target) return;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);
    InjectDLL(hProcess, selfPath);
