// ─── DLL injection ────────────────────────────────────────────────────────────

static bool InjectDLL(HANDLE hProcess, LPCWSTR dllPath) {
    const SIZE_T sz = (wcslen(dllPath) + 1) * sizeof(wchar_t);

    LPVOID pMem = VirtualAllocEx(hProcess, nullptr, sz,
                                 MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (!pMem) return false;

    if (!WriteProcessMemory(hProcess, pMem, dllPath, sz, nullptr)) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    auto pLL = reinterpret_cast<LPTHREAD_START_ROUTINE>(
        GetProcAddress(GetModuleHandleW(L"kernel32.dll"), "LoadLibraryW"));

    HANDLE hT = CreateRemoteThread(hProcess, nullptr, 0, pLL, pMem, 0, nullptr);
    if (!hT) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    WaitForSingleObject(hT, INFINITE);
    DWORD ec = 0;
    GetExitCodeThread(hT, &ec);
    CloseHandle(hT);
    VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
