// is harmless (DllMain won't re-run).

static volatile bool g_watcherRunning = false;
static HANDLE        g_watcherThread  = nullptr;

static DWORD WINAPI WatcherProc(LPVOID) {
    static const int kMax = 64;
    DWORD seen[kMax]{};
    int   seenN = 0;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);

    while (g_watcherRunning) {
        Sleep(1);

        HANDLE snap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
        if (snap == INVALID_HANDLE_VALUE) continue;

        PROCESSENTRY32W pe{};
        pe.dwSize = sizeof(pe);

        if (Process32FirstW(snap, &pe)) {
            do {
                // Skip PIDs we've already handled.
                bool already = false;
                for (int i = 0; i < seenN; i++)
                    if (seen[i] == pe.th32ProcessID) { already = true; break; }
                if (already) continue;

                // Case-insensitive name match — no parent-PID restriction.
                wchar_t lower[MAX_PATH]{};
                for (int i = 0; pe.szExeFile[i]; i++)
                    lower[i] = static_cast<wchar_t>(towlower(pe.szExeFile[i]));

                if (std::wstring_view(lower) == kChildExe) {
                    // Mark seen immediately to avoid retrying on failure.
                    if (seenN < kMax) seen[seenN++] = pe.th32ProcessID;

                    HANDLE hProc = OpenProcess(PROCESS_ALL_ACCESS, FALSE,
                                               pe.th32ProcessID);
                    if (hProc) {
                        InjectDLL(hProc, selfPath);
                        CloseHandle(hProc);
                    }
                }
            } while (Process32NextW(snap, &pe));
        }

        CloseHandle(snap);
