// ─── CreateProcess* hooks (fast-path child propagation) ───────────────────────

static std::wstring ExeBasenameW(LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring src;
    if (lpApp && *lpApp) {
        src = lpApp;
    } else if (lpCmd && *lpCmd) {
        if (lpCmd[0] == L'"') {
            const wchar_t* end = wcschr(lpCmd + 1, L'"');
            src = end ? std::wstring(lpCmd + 1, end) : std::wstring(lpCmd + 1);
        } else {
            const wchar_t* end = wcschr(lpCmd, L' ');
            src = end ? std::wstring(lpCmd, end) : std::wstring(lpCmd);
        }
    }
    const size_t slash = src.rfind(L'\\');
    if (slash != std::wstring::npos) src = src.substr(slash + 1);
    for (auto& c : src) c = static_cast<wchar_t>(towlower(c));
    return src;
}

static void PropagateToChild(HANDLE hProcess, LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring target(kChildExe);
    for (auto& c : target) c = static_cast<wchar_t>(towlower(c));
    if (ExeBasenameW(lpApp, lpCmd) != target) return;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);
    InjectDLL(hProcess, selfPath);
}

static std::wstring ToWide(LPCSTR s) {
    if (!s) return {};
    const int n = MultiByteToWideChar(CP_ACP, 0, s, -1, nullptr, 0);
    std::wstring w(n, L'\0');
    MultiByteToWideChar(CP_ACP, 0, s, -1, w.data(), n);
    return w;
}

// Shared logic for all CreateProcess variants after the real call succeeds.
static void OnChildCreated(LPPROCESS_INFORMATION lpPI, LPCWSTR lpApp, LPCWSTR lpCmd,
                            bool wasSuspended) {
    PropagateToChild(lpPI->hProcess, lpApp, lpCmd);
    if (!wasSuspended) ResumeThread(lpPI->hThread);
