BOOL WINAPI Hook_CreateProcessW(
    LPCWSTR lpApp, LPWSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCWSTR lpCwd,
    LPSTARTUPINFOW lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessW(lpApp, lpCmd, lpPA, lpTA, bInherit,
                                     dwFlags | CREATE_SUSPENDED,
                                     lpEnv, lpCwd, lpSI, lpPI);
    if (ok) OnChildCreated(lpPI, lpApp, lpCmd, wasSuspended);
    return ok;
