        GetProcAddress(GetModuleHandleW(L"kernel32.dll"), "LoadLibraryW"));

    HANDLE hT = CreateRemoteThread(hProcess, nullptr, 0, pLL, pMem, 0, nullptr);
    if (!hT) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
