/*
 * MultiInstance.dll
 *
 * Hooks mutex and process-creation APIs so that multiple instances of
 * DragonNest_x64.exe (and its Xigncode child xcoronahost.xem) can run
 * side-by-side.
 *
 * Mutex hooks            – rename target mutexes by appending the current PID.
 *
 * CreateProcess* hooks   – fast-path: catch xcoronahost.xem at the call site,
 *                          force it suspended, inject our DLL, resume.
 *                          Covers CreateProcessW/A AND CreateProcessAsUserW/A
 *                          (Xigncode commonly uses the AsUser variant).
 *
 * Watcher thread         – reliable fallback: 1 ms poll of the process list for
 *                          any new xcoronahost.xem, regardless of how it was
 *                          spawned or what its parent PID is (Xigncode can
 *                          spoof the parent via PROC_THREAD_ATTRIBUTE_PARENT).
 *
 * Target mutexes:
 *   MutexDragonNest                      (DragonNest_x64.exe)
 *   ae0f623d247862c91f9e5e54142179ef0    (xcoronahost.xem)
 *
 * Hook library: MinHook (https://github.com/TsudaKageyu/minhook)
 */

#include <Windows.h>
#include <TlHelp32.h>
#include <MinHook.h>

#include <string>
#include <string_view>

static HMODULE g_hSelf = nullptr;

// ─── Target mutex names ───────────────────────────────────────────────────────

static constexpr std::wstring_view kMutexW[] = {
    L"MutexDragonNest",
    L"ae0f623d247862c91f9e5e54142179ef0",
};
static constexpr std::string_view kMutexA[] = {
    "MutexDragonNest",
    "ae0f623d247862c91f9e5e54142179ef0",
};

static constexpr std::wstring_view kChildExe = L"xcoronahost.xem";

// ─── Mutex matching ───────────────────────────────────────────────────────────

template<typename Ch, size_t N>
static bool IsTargetMutex(const Ch* raw,
                           const std::basic_string_view<Ch> (&list)[N]) {
    if (!raw) return false;
    std::basic_string_view<Ch> sv(raw);
    for (const auto& t : list) {
        if (sv == t) return true;
        if (sv.size() > t.size()) {
            const size_t off = sv.size() - t.size();
            if (sv[off - 1] == Ch('\\') && sv.substr(off) == t)
                return true;
        }
    }
    return false;
}

// ─── PID suffix ───────────────────────────────────────────────────────────────

static std::wstring PidTagW() { return L"_" + std::to_wstring(GetCurrentProcessId()); }
static std::string  PidTagA() { return  "_" + std::to_string(GetCurrentProcessId());  }

// ─── DLL injection ────────────────────────────────────────────────────────────

static bool InjectDLL(HANDLE hProcess, LPCWSTR dllPath) {
    const SIZE_T sz = (wcslen(dllPath) + 1) * sizeof(wchar_t);

    LPVOID pMem = VirtualAllocEx(hProcess, nullptr, sz,
                                 MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (!pMem) return false;

    if (!WriteProcessMemory(hProcess, pMem, dllPath, sz, nullptr)) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    auto pLL = reinterpret_cast<LPTHREAD_START_ROUTINE>(
        GetProcAddress(GetModuleHandleW(L"kernel32.dll"), "LoadLibraryW"));

    HANDLE hT = CreateRemoteThread(hProcess, nullptr, 0, pLL, pMem, 0, nullptr);
    if (!hT) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    WaitForSingleObject(hT, INFINITE);
    DWORD ec = 0;
    GetExitCodeThread(hT, &ec);
    CloseHandle(hT);
    VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
    return ec != 0;
}

// ─── Watcher thread ───────────────────────────────────────────────────────────
// Polls every 1 ms for any new xcoronahost.xem process system-wide.
// No parent-PID filter — Xigncode can spoof the parent via
// PROC_THREAD_ATTRIBUTE_PARENT_PROCESS, which would fool a parent filter.
// LoadLibraryW is ref-counted, so injecting into an already-injected process
// is harmless (DllMain won't re-run).

static volatile bool g_watcherRunning = false;
static HANDLE        g_watcherThread  = nullptr;

static DWORD WINAPI WatcherProc(LPVOID) {
    static const int kMax = 64;
    DWORD seen[kMax]{};
    int   seenN = 0;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);

    while (g_watcherRunning) {
        Sleep(1);

        HANDLE snap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
        if (snap == INVALID_HANDLE_VALUE) continue;

        PROCESSENTRY32W pe{};
        pe.dwSize = sizeof(pe);

        if (Process32FirstW(snap, &pe)) {
            do {
                // Skip PIDs we've already handled.
                bool already = false;
                for (int i = 0; i < seenN; i++)
                    if (seen[i] == pe.th32ProcessID) { already = true; break; }
                if (already) continue;

                // Case-insensitive name match — no parent-PID restriction.
                wchar_t lower[MAX_PATH]{};
                for (int i = 0; pe.szExeFile[i]; i++)
                    lower[i] = static_cast<wchar_t>(towlower(pe.szExeFile[i]));

                if (std::wstring_view(lower) == kChildExe) {
                    // Mark seen immediately to avoid retrying on failure.
                    if (seenN < kMax) seen[seenN++] = pe.th32ProcessID;

                    HANDLE hProc = OpenProcess(PROCESS_ALL_ACCESS, FALSE,
                                               pe.th32ProcessID);
                    if (hProc) {
                        InjectDLL(hProc, selfPath);
                        CloseHandle(hProc);
                    }
                }
            } while (Process32NextW(snap, &pe));
        }

        CloseHandle(snap);
    }

    return 0;
}

// ─── Typedefs ─────────────────────────────────────────────────────────────────

using FnCreateMutexW        = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL, LPCWSTR);
using FnCreateMutexA        = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL, LPCSTR);
using FnCreateMutexExW      = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCWSTR, DWORD, DWORD);
using FnCreateMutexExA      = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCSTR,  DWORD, DWORD);
using FnOpenMutexW          = HANDLE(WINAPI*)(DWORD, BOOL, LPCWSTR);
using FnOpenMutexA          = HANDLE(WINAPI*)(DWORD, BOOL, LPCSTR);
using FnCreateProcessW      = BOOL(WINAPI*)(LPCWSTR, LPWSTR,
                                  LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                  BOOL, DWORD, LPVOID, LPCWSTR,
                                  LPSTARTUPINFOW, LPPROCESS_INFORMATION);
using FnCreateProcessA      = BOOL(WINAPI*)(LPCSTR, LPSTR,
                                  LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                  BOOL, DWORD, LPVOID, LPCSTR,
                                  LPSTARTUPINFOA, LPPROCESS_INFORMATION);
using FnCreateProcessAsUserW = BOOL(WINAPI*)(HANDLE, LPCWSTR, LPWSTR,
                                  LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                  BOOL, DWORD, LPVOID, LPCWSTR,
                                  LPSTARTUPINFOW, LPPROCESS_INFORMATION);
using FnCreateProcessAsUserA = BOOL(WINAPI*)(HANDLE, LPCSTR, LPSTR,
                                  LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                  BOOL, DWORD, LPVOID, LPCSTR,
                                  LPSTARTUPINFOA, LPPROCESS_INFORMATION);

static FnCreateMutexW        g_CreateMutexW        = nullptr;
static FnCreateMutexA        g_CreateMutexA        = nullptr;
static FnCreateMutexExW      g_CreateMutexExW      = nullptr;
static FnCreateMutexExA      g_CreateMutexExA      = nullptr;
static FnOpenMutexW          g_OpenMutexW          = nullptr;
static FnOpenMutexA          g_OpenMutexA          = nullptr;
static FnCreateProcessW      g_CreateProcessW      = nullptr;
static FnCreateProcessA      g_CreateProcessA      = nullptr;
static FnCreateProcessAsUserW g_CreateProcessAsUserW = nullptr;
static FnCreateProcessAsUserA g_CreateProcessAsUserA = nullptr;

// ─── Mutex hooks ──────────────────────────────────────────────────────────────

HANDLE WINAPI Hook_CreateMutexW(LPSECURITY_ATTRIBUTES a, BOOL b, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexW))
        return g_CreateMutexW(a, b, (std::wstring(name) + PidTagW()).c_str());
    return g_CreateMutexW(a, b, name);
}

HANDLE WINAPI Hook_CreateMutexA(LPSECURITY_ATTRIBUTES a, BOOL b, LPCSTR name) {
    if (IsTargetMutex(name, kMutexA))
        return g_CreateMutexA(a, b, (std::string(name) + PidTagA()).c_str());
    return g_CreateMutexA(a, b, name);
}

HANDLE WINAPI Hook_CreateMutexExW(LPSECURITY_ATTRIBUTES a, LPCWSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexW))
        return g_CreateMutexExW(a, (std::wstring(name) + PidTagW()).c_str(), f, d);
    return g_CreateMutexExW(a, name, f, d);
}

HANDLE WINAPI Hook_CreateMutexExA(LPSECURITY_ATTRIBUTES a, LPCSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexA))
        return g_CreateMutexExA(a, (std::string(name) + PidTagA()).c_str(), f, d);
    return g_CreateMutexExA(a, name, f, d);
}

HANDLE WINAPI Hook_OpenMutexW(DWORD acc, BOOL inh, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexW))
        return g_OpenMutexW(acc, inh, (std::wstring(name) + PidTagW()).c_str());
    return g_OpenMutexW(acc, inh, name);
}

HANDLE WINAPI Hook_OpenMutexA(DWORD acc, BOOL inh, LPCSTR name) {
    if (IsTargetMutex(name, kMutexA))
        return g_OpenMutexA(acc, inh, (std::string(name) + PidTagA()).c_str());
    return g_OpenMutexA(acc, inh, name);
}

// ─── CreateProcess* hooks (fast-path child propagation) ───────────────────────

static std::wstring ExeBasenameW(LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring src;
    if (lpApp && *lpApp) {
        src = lpApp;
    } else if (lpCmd && *lpCmd) {
        if (lpCmd[0] == L'"') {
            const wchar_t* end = wcschr(lpCmd + 1, L'"');
            src = end ? std::wstring(lpCmd + 1, end) : std::wstring(lpCmd + 1);
        } else {
            const wchar_t* end = wcschr(lpCmd, L' ');
            src = end ? std::wstring(lpCmd, end) : std::wstring(lpCmd);
        }
    }
    const size_t slash = src.rfind(L'\\');
    if (slash != std::wstring::npos) src = src.substr(slash + 1);
    for (auto& c : src) c = static_cast<wchar_t>(towlower(c));
    return src;
}

static void PropagateToChild(HANDLE hProcess, LPCWSTR lpApp, LPCWSTR lpCmd) {
    std::wstring target(kChildExe);
    for (auto& c : target) c = static_cast<wchar_t>(towlower(c));
    if (ExeBasenameW(lpApp, lpCmd) != target) return;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);
    InjectDLL(hProcess, selfPath);
}

static std::wstring ToWide(LPCSTR s) {
    if (!s) return {};
    const int n = MultiByteToWideChar(CP_ACP, 0, s, -1, nullptr, 0);
    std::wstring w(n, L'\0');
    MultiByteToWideChar(CP_ACP, 0, s, -1, w.data(), n);
    return w;
}

// Shared logic for all CreateProcess variants after the real call succeeds.
static void OnChildCreated(LPPROCESS_INFORMATION lpPI, LPCWSTR lpApp, LPCWSTR lpCmd,
                            bool wasSuspended) {
    PropagateToChild(lpPI->hProcess, lpApp, lpCmd);
    if (!wasSuspended) ResumeThread(lpPI->hThread);
}

BOOL WINAPI Hook_CreateProcessW(
    LPCWSTR lpApp, LPWSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCWSTR lpCwd,
    LPSTARTUPINFOW lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessW(lpApp, lpCmd, lpPA, lpTA, bInherit,
                                     dwFlags | CREATE_SUSPENDED,
                                     lpEnv, lpCwd, lpSI, lpPI);
    if (ok) OnChildCreated(lpPI, lpApp, lpCmd, wasSuspended);
    return ok;
}

BOOL WINAPI Hook_CreateProcessA(
    LPCSTR lpApp, LPSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCSTR lpCwd,
    LPSTARTUPINFOA lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessA(lpApp, lpCmd, lpPA, lpTA, bInherit,
                                     dwFlags | CREATE_SUSPENDED,
                                     lpEnv, lpCwd, lpSI, lpPI);
    if (ok) {
        const std::wstring wApp = ToWide(lpApp);
        const std::wstring wCmd = ToWide(lpCmd);
        OnChildCreated(lpPI, lpApp ? wApp.c_str() : nullptr,
                             lpCmd ? wCmd.c_str() : nullptr, wasSuspended);
    }
    return ok;
}

// advapi32 variants — Xigncode commonly uses these to run xcoronahost.xem
// under a specific token without needing the caller to be elevated.

BOOL WINAPI Hook_CreateProcessAsUserW(
    HANDLE hToken,
    LPCWSTR lpApp, LPWSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCWSTR lpCwd,
    LPSTARTUPINFOW lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessAsUserW(hToken, lpApp, lpCmd, lpPA, lpTA, bInherit,
                                           dwFlags | CREATE_SUSPENDED,
                                           lpEnv, lpCwd, lpSI, lpPI);
    if (ok) OnChildCreated(lpPI, lpApp, lpCmd, wasSuspended);
    return ok;
}

BOOL WINAPI Hook_CreateProcessAsUserA(
    HANDLE hToken,
    LPCSTR lpApp, LPSTR lpCmd,
    LPSECURITY_ATTRIBUTES lpPA, LPSECURITY_ATTRIBUTES lpTA,
    BOOL bInherit, DWORD dwFlags, LPVOID lpEnv, LPCSTR lpCwd,
    LPSTARTUPINFOA lpSI, LPPROCESS_INFORMATION lpPI)
{
    const bool wasSuspended = (dwFlags & CREATE_SUSPENDED) != 0;
    const BOOL ok = g_CreateProcessAsUserA(hToken, lpApp, lpCmd, lpPA, lpTA, bInherit,
                                           dwFlags | CREATE_SUSPENDED,
                                           lpEnv, lpCwd, lpSI, lpPI);
    if (ok) {
        const std::wstring wApp = ToWide(lpApp);
        const std::wstring wCmd = ToWide(lpCmd);
        OnChildCreated(lpPI, lpApp ? wApp.c_str() : nullptr,
                             lpCmd ? wCmd.c_str() : nullptr, wasSuspended);
    }
    return ok;
}

// ─── Hook table ───────────────────────────────────────────────────────────────

struct HookEntry { const wchar_t* mod; const char* fn; LPVOID hook; LPVOID* orig; };

static const HookEntry kHooks[] = {
    // Mutex hooks
    { L"kernel32", "CreateMutexW",         (LPVOID)Hook_CreateMutexW,         (LPVOID*)&g_CreateMutexW         },
    { L"kernel32", "CreateMutexA",         (LPVOID)Hook_CreateMutexA,         (LPVOID*)&g_CreateMutexA         },
    { L"kernel32", "CreateMutexExW",       (LPVOID)Hook_CreateMutexExW,       (LPVOID*)&g_CreateMutexExW       },
    { L"kernel32", "CreateMutexExA",       (LPVOID)Hook_CreateMutexExA,       (LPVOID*)&g_CreateMutexExA       },
    { L"kernel32", "OpenMutexW",           (LPVOID)Hook_OpenMutexW,           (LPVOID*)&g_OpenMutexW           },
    { L"kernel32", "OpenMutexA",           (LPVOID)Hook_OpenMutexA,           (LPVOID*)&g_OpenMutexA           },
    // Process creation hooks — kernel32 variants
    { L"kernel32", "CreateProcessW",       (LPVOID)Hook_CreateProcessW,       (LPVOID*)&g_CreateProcessW       },
    { L"kernel32", "CreateProcessA",       (LPVOID)Hook_CreateProcessA,       (LPVOID*)&g_CreateProcessA       },
    // Process creation hooks — advapi32 variants (used by Xigncode)
    { L"advapi32", "CreateProcessAsUserW", (LPVOID)Hook_CreateProcessAsUserW, (LPVOID*)&g_CreateProcessAsUserW },
    { L"advapi32", "CreateProcessAsUserA", (LPVOID)Hook_CreateProcessAsUserA, (LPVOID*)&g_CreateProcessAsUserA },
};

static bool InstallHooks() {
    if (MH_Initialize() != MH_OK) return false;
    for (const auto& h : kHooks)
        if (MH_CreateHookApi(h.mod, h.fn, h.hook, h.orig) != MH_OK) return false;
    return MH_EnableHook(MH_ALL_HOOKS) == MH_OK;
}

static void RemoveHooks() {
    MH_DisableHook(MH_ALL_HOOKS);
    MH_Uninitialize();
}

// ─── DllMain ─────────────────────────────────────────────────────────────────

BOOL APIENTRY DllMain(HMODULE hModule, DWORD reason, LPVOID /*reserved*/) {
    switch (reason) {
    case DLL_PROCESS_ATTACH:
        DisableThreadLibraryCalls(hModule);
        g_hSelf = hModule;
        InstallHooks();
        g_watcherRunning = true;
        g_watcherThread  = CreateThread(nullptr, 0, WatcherProc, nullptr, 0, nullptr);
        break;

    case DLL_PROCESS_DETACH:
        g_watcherRunning = false;
        if (g_watcherThread) {
            WaitForSingleObject(g_watcherThread, 200);
            CloseHandle(g_watcherThread);
            g_watcherThread = nullptr;
        }
        RemoveHooks();
        break;
    }
    return TRUE;
}

