/*
 * MultiInstance.dll
 *
 * Hooks mutex and process-creation APIs so that multiple instances of
 * DragonNest_x64.exe (and its Xigncode child xcoronahost.xem) can run
 * side-by-side.
 *
 * Why NtCreateMutant / NtOpenMutant?
 *   The mutex \BaseNamedObjects\ae0f623d247862c91f9e5e54142179ef0 shows a
 *   PointerCount of 0x10000 (65536) in Process Hacker — the Windows kernel's
 *   initial refcount for objects created via the raw NT syscall stub in ntdll.
 *   This means Xigncode calls NtCreateMutant directly, bypassing the high-level
 *   CreateMutexW wrapper entirely.  Hooking at the ntdll level catches ALL
 *   mutex operations regardless of which Win32 (or no) wrapper is used.
 *
 * CreateProcess* hooks   – fast-path: suspend xcoronahost.xem at creation,
 *                          inject, resume.  Covers kernel32 + advapi32 variants.
 *
 * Watcher thread         – reliable fallback: 1 ms poll for any new
 *                          xcoronahost.xem, regardless of spawn mechanism or
 *                          spoofed parent PID.
 *
 * Hook library: MinHook (https://github.com/TsudaKageyu/minhook)
 */

#define WIN32_LEAN_AND_MEAN
#include <Windows.h>
#include <TlHelp32.h>
#include <winternl.h>       // OBJECT_ATTRIBUTES, UNICODE_STRING
#include <MinHook.h>

#include <string>
#include <string_view>

static HMODULE g_hSelf = nullptr;

// ─── Target mutex names ───────────────────────────────────────────────────────

static constexpr std::wstring_view kMutexTargets[] = {
    L"MutexDragonNest",
    L"ae0f623d247862c91f9e5e54142179ef0",
};

static constexpr std::string_view kMutexTargetsA[] = {
    "MutexDragonNest",
    "ae0f623d247862c91f9e5e54142179ef0",
};

static constexpr std::wstring_view kChildExe = L"xcoronahost.xem";

// ─── Mutex name matching ──────────────────────────────────────────────────────
// Accepts bare names ("MutexDragonNest") and any namespace-prefixed form
// ("\BaseNamedObjects\MutexDragonNest", "Global\MutexDragonNest", etc.)
// Works with both null-terminated C strings and explicitly-sized views.

template<typename Ch, size_t N>
static bool IsTargetMutex(std::basic_string_view<Ch> sv,
                           const std::basic_string_view<Ch> (&list)[N]) {
    for (const auto& t : list) {
        if (sv == t) return true;
        if (sv.size() > t.size()) {
            const size_t off = sv.size() - t.size();
            if (sv[off - 1] == Ch('\\') && sv.substr(off) == t)
                return true;
        }
    }
    return false;
}

template<typename Ch, size_t N>
static bool IsTargetMutex(const Ch* raw,
                           const std::basic_string_view<Ch> (&list)[N]) {
    if (!raw) return false;
    return IsTargetMutex(std::basic_string_view<Ch>(raw), list);
}

// ─── PID suffix ───────────────────────────────────────────────────────────────

static std::wstring PidTagW() { return L"_" + std::to_wstring(GetCurrentProcessId()); }
static std::string  PidTagA() { return  "_" + std::to_string(GetCurrentProcessId());  }

// ─── DLL injection ────────────────────────────────────────────────────────────

static bool InjectDLL(HANDLE hProcess, LPCWSTR dllPath) {
    const SIZE_T sz = (wcslen(dllPath) + 1) * sizeof(wchar_t);

    LPVOID pMem = VirtualAllocEx(hProcess, nullptr, sz,
                                 MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (!pMem) return false;

    if (!WriteProcessMemory(hProcess, pMem, dllPath, sz, nullptr)) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    auto pLL = reinterpret_cast<LPTHREAD_START_ROUTINE>(
        GetProcAddress(GetModuleHandleW(L"kernel32.dll"), "LoadLibraryW"));

    HANDLE hT = CreateRemoteThread(hProcess, nullptr, 0, pLL, pMem, 0, nullptr);
    if (!hT) {
        VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
        return false;
    }

    WaitForSingleObject(hT, INFINITE);
    DWORD ec = 0;
    GetExitCodeThread(hT, &ec);
    CloseHandle(hT);
    VirtualFreeEx(hProcess, pMem, 0, MEM_RELEASE);
    return ec != 0;
}

// ─── Watcher thread ───────────────────────────────────────────────────────────

static volatile bool g_watcherRunning = false;
static HANDLE        g_watcherThread  = nullptr;

static DWORD WINAPI WatcherProc(LPVOID) {
    static const int kMax = 64;
    DWORD seen[kMax]{};
    int   seenN = 0;

    wchar_t selfPath[MAX_PATH]{};
    GetModuleFileNameW(g_hSelf, selfPath, MAX_PATH);

    while (g_watcherRunning) {
        Sleep(1);

        HANDLE snap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
        if (snap == INVALID_HANDLE_VALUE) continue;

        PROCESSENTRY32W pe{};
        pe.dwSize = sizeof(pe);

        if (Process32FirstW(snap, &pe)) {
            do {
                bool already = false;
                for (int i = 0; i < seenN; i++)
                    if (seen[i] == pe.th32ProcessID) { already = true; break; }
                if (already) continue;

                wchar_t lower[MAX_PATH]{};
                for (int i = 0; pe.szExeFile[i]; i++)
                    lower[i] = static_cast<wchar_t>(towlower(pe.szExeFile[i]));

                if (std::wstring_view(lower) == kChildExe) {
                    if (seenN < kMax) seen[seenN++] = pe.th32ProcessID;

                    HANDLE hProc = OpenProcess(PROCESS_ALL_ACCESS, FALSE,
                                               pe.th32ProcessID);
                    if (hProc) {
                        InjectDLL(hProc, selfPath);
                        CloseHandle(hProc);
                    }
                }
            } while (Process32NextW(snap, &pe));
        }

        CloseHandle(snap);
    }
    return 0;
}

// ─── Typedefs ─────────────────────────────────────────────────────────────────

// ntdll — raw NT syscall stubs
using FnNtCreateMutant = NTSTATUS(NTAPI*)(PHANDLE, ACCESS_MASK,
                                           POBJECT_ATTRIBUTES, BOOLEAN);
using FnNtOpenMutant   = NTSTATUS(NTAPI*)(PHANDLE, ACCESS_MASK,
                                           POBJECT_ATTRIBUTES);

// kernel32 / advapi32 — high-level wrappers (kept for belt-and-suspenders)
using FnCreateMutexW         = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL, LPCWSTR);
using FnCreateMutexA         = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL, LPCSTR);
using FnCreateMutexExW       = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCWSTR, DWORD, DWORD);
using FnCreateMutexExA       = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCSTR,  DWORD, DWORD);
using FnOpenMutexW           = HANDLE(WINAPI*)(DWORD, BOOL, LPCWSTR);
using FnOpenMutexA           = HANDLE(WINAPI*)(DWORD, BOOL, LPCSTR);
using FnCreateProcessW       = BOOL(WINAPI*)(LPCWSTR, LPWSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCWSTR,
                                   LPSTARTUPINFOW, LPPROCESS_INFORMATION);
using FnCreateProcessA       = BOOL(WINAPI*)(LPCSTR, LPSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCSTR,
                                   LPSTARTUPINFOA, LPPROCESS_INFORMATION);
using FnCreateProcessAsUserW = BOOL(WINAPI*)(HANDLE, LPCWSTR, LPWSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCWSTR,
                                   LPSTARTUPINFOW, LPPROCESS_INFORMATION);
using FnCreateProcessAsUserA = BOOL(WINAPI*)(HANDLE, LPCSTR, LPSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCSTR,
                                   LPSTARTUPINFOA, LPPROCESS_INFORMATION);

static FnNtCreateMutant       g_NtCreateMutant       = nullptr;
static FnNtOpenMutant         g_NtOpenMutant         = nullptr;
static FnCreateMutexW         g_CreateMutexW         = nullptr;
static FnCreateMutexA         g_CreateMutexA         = nullptr;
static FnCreateMutexExW       g_CreateMutexExW       = nullptr;
static FnCreateMutexExA       g_CreateMutexExA       = nullptr;
static FnOpenMutexW           g_OpenMutexW           = nullptr;
static FnOpenMutexA           g_OpenMutexA           = nullptr;
static FnCreateProcessW       g_CreateProcessW       = nullptr;
static FnCreateProcessA       g_CreateProcessA       = nullptr;
static FnCreateProcessAsUserW g_CreateProcessAsUserW = nullptr;
static FnCreateProcessAsUserA g_CreateProcessAsUserA = nullptr;

// ─── NT-level mutex hooks ─────────────────────────────────────────────────────
// These sit below CreateMutexW/A and catch *every* mutex operation, including
// direct NtCreateMutant calls that bypass the Win32 layer entirely.

// Build a renamed OBJECT_ATTRIBUTES on the stack and call through.
// The UNICODE_STRING and std::wstring backing it live in the caller's frame,
// so they're valid for the duration of the NT call.

NTSTATUS NTAPI Hook_NtCreateMutant(PHANDLE hMutant, ACCESS_MASK access,
                                    POBJECT_ATTRIBUTES oa, BOOLEAN initOwner) {
    if (oa && oa->ObjectName && oa->ObjectName->Buffer) {
        // UNICODE_STRING may not be null-terminated — use explicit length.
        std::wstring name(oa->ObjectName->Buffer,
                          oa->ObjectName->Length / sizeof(wchar_t));

        if (IsTargetMutex(std::wstring_view(name), kMutexTargets)) {
            std::wstring renamed = name + PidTagW();
            UNICODE_STRING uRenamed{};
            uRenamed.Buffer        = renamed.data();
            uRenamed.Length        = static_cast<USHORT>(renamed.size() * sizeof(wchar_t));
            uRenamed.MaximumLength = uRenamed.Length;

            OBJECT_ATTRIBUTES oaRenamed = *oa;
            oaRenamed.ObjectName = &uRenamed;
            return g_NtCreateMutant(hMutant, access, &oaRenamed, initOwner);
        }
    }
    return g_NtCreateMutant(hMutant, access, oa, initOwner);
}

NTSTATUS NTAPI Hook_NtOpenMutant(PHANDLE hMutant, ACCESS_MASK access,
                                  POBJECT_ATTRIBUTES oa) {
    if (oa && oa->ObjectName && oa->ObjectName->Buffer) {
        std::wstring name(oa->ObjectName->Buffer,
                          oa->ObjectName->Length / sizeof(wchar_t));

        if (IsTargetMutex(std::wstring_view(name), kMutexTargets)) {
            std::wstring renamed = name + PidTagW();
            UNICODE_STRING uRenamed{};
            uRenamed.Buffer        = renamed.data();
            uRenamed.Length        = static_cast<USHORT>(renamed.size() * sizeof(wchar_t));
            uRenamed.MaximumLength = uRenamed.Length;

            OBJECT_ATTRIBUTES oaRenamed = *oa;
            oaRenamed.ObjectName = &uRenamed;
            return g_NtOpenMutant(hMutant, access, &oaRenamed);
        }
    }
    return g_NtOpenMutant(hMutant, access, oa);
}

// ─── Win32-level mutex hooks (belt-and-suspenders) ───────────────────────────

HANDLE WINAPI Hook_CreateMutexW(LPSECURITY_ATTRIBUTES a, BOOL b, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexTargets))
        return g_CreateMutexW(a, b, (std::wstring(name) + PidTagW()).c_str());
    return g_CreateMutexW(a, b, name);
}
HANDLE WINAPI Hook_CreateMutexA(LPSECURITY_ATTRIBUTES a, BOOL b, LPCSTR name) {
    if (IsTargetMutex(name, kMutexTargetsA))
        return g_CreateMutexA(a, b, (std::string(name) + PidTagA()).c_str());
    return g_CreateMutexA(a, b, name);
}
HANDLE WINAPI Hook_CreateMutexExW(LPSECURITY_ATTRIBUTES a, LPCWSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexTargets))
        return g_CreateMutexExW(a, (std::wstring(name) + PidTagW()).c_str(), f, d);
    return g_CreateMutexExW(a, name, f, d);
}
HANDLE WINAPI Hook_CreateMutexExA(LPSECURITY_ATTRIBUTES a, LPCSTR name, DWORD f, DWORD d) {
    if (IsTargetMutex(name, kMutexTargetsA))
        return g_CreateMutexExA(a, (std::string(name) + PidTagA()).c_str(), f, d);
    return g_CreateMutexExA(a, name, f, d);
}
HANDLE WINAPI Hook_OpenMutexW(DWORD acc, BOOL inh, LPCWSTR name) {
    if (IsTargetMutex(name, kMutexTargets))
        return g_OpenMutexW(acc, inh, (std::wstring(name) + PidTagW()).c_str());
    return g_OpenMutexW(acc, inh, name);
}
HANDLE WINAPI Hook_OpenMutexA(DWORD acc, BOOL inh, LPCSTR name) {
