using FnNtCreateMutant = NTSTATUS(NTAPI*)(PHANDLE, ACCESS_MASK,
                                           POBJECT_ATTRIBUTES, BOOLEAN);
using FnNtOpenMutant   = NTSTATUS(NTAPI*)(PHANDLE, ACCESS_MASK,
                                           POBJECT_ATTRIBUTES);

