using FnCreateMutexA         = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, BOOL, LPCSTR);
using FnCreateMutexExW       = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCWSTR, DWORD, DWORD);
using FnCreateMutexExA       = HANDLE(WINAPI*)(LPSECURITY_ATTRIBUTES, LPCSTR,  DWORD, DWORD);
using FnOpenMutexW           = HANDLE(WINAPI*)(DWORD, BOOL, LPCWSTR);
using FnOpenMutexA           = HANDLE(WINAPI*)(DWORD, BOOL, LPCSTR);
using FnCreateProcessW       = BOOL(WINAPI*)(LPCWSTR, LPWSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCWSTR,
                                   LPSTARTUPINFOW, LPPROCESS_INFORMATION);
using FnCreateProcessA       = BOOL(WINAPI*)(LPCSTR, LPSTR,
                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCSTR,
                                   LPSTARTUPINFOA, LPPROCESS_INFORMATION);
