                                   LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
                                   BOOL, DWORD, LPVOID, LPCSTR,
                                   LPSTARTUPINFOA, LPPROCESS_INFORMATION);

static FnNtCreateMutant       g_NtCreateMutant       = nullptr;
static FnNtOpenMutant         g_NtOpenMutant         = nullptr;
static FnCreateMutexW         g_CreateMutexW         = nullptr;
static FnCreateMutexA         g_CreateMutexA         = nullptr;
static FnCreateMutexExW       g_CreateMutexExW       = nullptr;
static FnCreateMutexExA       g_CreateMutexExA       = nullptr;
static FnOpenMutexW           g_OpenMutexW           = nullptr;
static FnOpenMutexA           g_OpenMutexA           = nullptr;
static FnCreateProcessW       g_CreateProcessW       = nullptr;
static FnCreateProcessA       g_CreateProcessA       = nullptr;
static FnCreateProcessAsUserW g_CreateProcessAsUserW = nullptr;
static FnCreateProcessAsUserA g_CreateProcessAsUserA = nullptr;

// ─── NT-level mutex hooks ─────────────────────────────────────────────────────
// These sit below CreateMutexW/A and catch *every* mutex operation, including
// direct NtCreateMutant calls that bypass the Win32 layer entirely.

// Build a renamed OBJECT_ATTRIBUTES on the stack and call through.
// The UNICODE_STRING and std::wstring backing it live in the caller's frame,
// so they're valid for the duration of the NT call.

NTSTATUS NTAPI Hook_NtCreateMutant(PHANDLE hMutant, ACCESS_MASK access,
                                    POBJECT_ATTRIBUTES oa, BOOLEAN initOwner) {
    if (oa && oa->ObjectName && oa->ObjectName->Buffer) {
        // UNICODE_STRING may not be null-terminated — use explicit length.
        std::wstring name(oa->ObjectName->Buffer,
                          oa->ObjectName->Length / sizeof(wchar_t));

        if (IsTargetMutex(std::wstring_view(name), kMutexTargets)) {
            std::wstring renamed = name + PidTagW();
            UNICODE_STRING uRenamed{};
            uRenamed.Buffer        = renamed.data();
            uRenamed.Length        = static_cast<USHORT>(renamed.size() * sizeof(wchar_t));
            uRenamed.MaximumLength = uRenamed.Length;

            OBJECT_ATTRIBUTES oaRenamed = *oa;
            oaRenamed.ObjectName = &uRenamed;
            return g_NtCreateMutant(hMutant, access, &oaRenamed, initOwner);
        }
    }
    return g_NtCreateMutant(hMutant, access, oa, initOwner);
